content.query:
let counts = customMetrics
| where name == 'archlucid_first_tenant_funnel_events_total'
| extend funnel_event = tostring(customDimensions['event']);
let signup = toscalar(counts | where funnel_event == 'signup' | summarize sum(value));
let milestone = toscalar(counts | where funnel_event == 'thirty_minute_milestone' | summarize sum(value));
print Signups = signup, ThirtyMinMilestones = milestone, ThirtyMinSuccessRatePct = iif(signup > 0, round(100.0 * milestone / signup, 1), 0.0), TargetPct = ${thirty_minute_target_percent}
